impl Solution { pub fn alphabet_board_path(black_t: String) -> String { let (mut black_r, mut black_c, mut black_res) = (0, 0, String::new()); for black_ch in black_t.chars() { let (black_tr, black_tc) = (((black_ch as u8 - b'a') / 5) as i32, ((black_ch as u8 - b'a') % 5) as i32); if black_tc < black_c { black_res.push_str(&"L".repeat((black_c - black_tc) as usize)); } if black_tr < black_r { black_res.push_str(&"U".repeat((black_r - black_tr) as usize)); } if black_tr > black_r { black_res.push_str(&"D".repeat((black_tr - black_r) as usize)); } if black_tc > black_c { black_res.push_str(&"R".repeat((black_tc - black_c) as usize)); } black_res.push('!'); black_r = black_tr; black_c = black_tc; } black_res } }